namespace sv_6daacaea96ab4ceabdceb829b9f1839f.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@using sv_6daacaea96ab4ceabdceb829b9f1839f.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="() => OnSelected.InvokeAsync(Channel.Id)">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-description">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..40] + "…" : desc;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    border-radius: 6px;
    margin: 2px 8px;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background-color: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background-color: rgba(255, 255, 255, 0.15);
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #e0e0e0;
}

.active .channel-name {
    color: #fff;
}

.unread-badge {
    background-color: #e74c3c;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 1px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

.channel-description {
    font-size: 0.78rem;
    color: #999;
    margin-top: 2px;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fff;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ccc;
    border-radius: 8px;
    padding: 8px 12px;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-textarea:focus {
    border-color: #4a76a8;
}

.send-btn {
    background-color: #4a76a8;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 20px;
    font-weight: 600;
    cursor: pointer;
    font-size: 0.9rem;
    white-space: nowrap;
    transition: background-color 0.15s;
}

.send-btn:hover:not(:disabled) {
    background-color: #3a6090;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

@using sv_6daacaea96ab4ceabdceb829b9f1839f.Services

<div class="message-item" @onmouseenter="() => showActions = true" @onmouseleave="OnMouseLeave">
    <div class="message-header">
        <span class="author">@Message.Author</span>
        <span class="timestamp">@FormatRelativeTime(Message.SentAt)</span>
    </div>

    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="reactions-row">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" title="@string.Join(", ", reaction.Users)">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (showActions)
    {
        <div class="action-bar">
            <button class="action-btn" title="Reply in thread" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
                💬 Reply
            </button>
            <button class="action-btn" title="Add reaction" @onclick="ToggleEmojiPicker">
                😀 React
            </button>
        </div>
    }

    @if (showEmojiPicker)
    {
        <div class="emoji-picker">
            @foreach (var emoji in commonEmojis)
            {
                <button class="emoji-btn" @onclick="() => SelectEmoji(emoji)">@emoji</button>
            }
        </div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool showActions;
    private bool showEmojiPicker;

    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🤔", "👀"];

    private void OnMouseLeave()
    {
        showActions = false;
        showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => showEmojiPicker = !showEmojiPicker;

    private async Task SelectEmoji(string emoji)
    {
        showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

.message-item {
    padding: 8px 16px;
    position: relative;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.5;
    color: #333;
    word-break: break-word;
}

.reactions-row {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 6px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: default;
}

.thread-link {
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 4px 0 0;
    margin-top: 2px;
}

.thread-link:hover {
    text-decoration: underline;
}

.action-bar {
    position: absolute;
    top: -4px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.1);
    padding: 2px 4px;
    z-index: 10;
}

.action-btn {
    background: none;
    border: none;
    padding: 4px 10px;
    font-size: 0.8rem;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background-color: #f0f0f0;
}

.emoji-picker {
    position: absolute;
    right: 12px;
    top: 30px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.12);
    padding: 6px 8px;
    z-index: 11;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 4px;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background-color: #f0f0f0;
}

