{"path": "/tmp/sv-6daacaea96ab4ceabdceb829b9f1839f/Components/Chat/MessageInput.razor", "file_text": "<div class="message-input-area">
    <textarea class="message-textarea"
              placeholder="@Placeholder"
              @bind="messageText"
              @onkeydown="HandleKeyDown"
              rows="2"></textarea>
    <button class="send-btn" @onclick="Send" disabled="@string.IsNullOrWhiteSpace(messageText)">
        @ButtonLabel
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message…";
    [Parameter] public string ButtonLabel { get; set; } = "Send";
    [Parameter] public EventCallback<string> OnSend { get; set; }

    private string messageText = string.Empty;

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await Send();
        }
    }

    private async Task Send()
    {
        var text = messageText.Trim();
        if (string.IsNullOrEmpty(text))
            return;

        messageText = string.Empty;
        await OnSend.InvokeAsync(text);
    }
}
"}

