@using sv_6daacaea96ab4ceabdceb829b9f1839f.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h3>Channels</h3>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == ActiveChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int? ActiveChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    background-color: #2c2f33;
    color: #e0e0e0;
    display: flex;
    flex-direction: column;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.08);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

@using sv_6daacaea96ab4ceabdceb829b9f1839f.Services
@inject IJSRuntime JS

<div class="message-list-container">
    @if (IsLoading && Messages.Count == 0)
    {
        <div class="loading-indicator">Loading messages…</div>
    }
    else
    {
        <div class="message-scroll" @ref="scrollContainer" @onscroll="HandleScroll">
            @if (IsLoading)
            {
                <div class="loading-older">Loading older messages…</div>
            }
            @if (!HasMore && Messages.Count > 0)
            {
                <div class="beginning-marker">Beginning of conversation</div>
            }
            @foreach (var message in Messages)
            {
                <MessageItem Message="message"
                             ReplyCount="GetReplyCount(message.Id)"
                             OnReplyClicked="OnReplyClicked"
                             OnReactionAdded="OnReactionAdded" />
            }
        </div>
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = [];
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private ElementReference scrollContainer;
    private bool scrolledToBottom;

    private int GetReplyCount(int messageId)
        => ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            await ScrollToBottom();
        }
    }

    private async Task HandleScroll()
    {
        if (!HasMore || IsLoading)
            return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('[b-message-list]')?.scrollTop ?? -1");
        if (scrollTop >= 0 && scrollTop < 50)
        {
            await OnLoadMore.InvokeAsync();
        }
    }

    public async Task ScrollToBottom()
    {
        try
        {
            await JS.InvokeVoidAsync("eval",
                "setTimeout(() => { let el = document.querySelector('.message-scroll'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
        }
        catch { /* component may be disposed */ }
    }
}

.message-list-container {
    flex: 1;
    display: flex;
    flex-direction: column;
    overflow: hidden;
    min-height: 0;
}

.message-scroll {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.loading-indicator {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 0.9rem;
}

.loading-older {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 0.82rem;
}

.beginning-marker {
    text-align: center;
    padding: 16px;
    color: #bbb;
    font-size: 0.82rem;
    font-style: italic;
}

@using sv_6daacaea96ab4ceabdceb829b9f1839f.Services

<div class="thread-panel">
    <div class="thread-header">
        <h4>Thread</h4>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-quote">
            <div class="quote-author">@RootMessage.Author</div>
            <div class="quote-content">@RootMessage.Content</div>
        </div>

        <div class="thread-replies">
            @if (IsLoading)
            {
                <div class="thread-loading">Loading replies…</div>
            }
            else if (Replies.Count == 0)
            {
                <div class="thread-empty">No replies yet. Start the conversation!</div>
            }
            else
            {
                @foreach (var reply in Replies)
                {
                    <div class="thread-reply">
                        <div class="reply-header">
                            <span class="reply-author">@reply.Author</span>
                            <span class="reply-time">@FormatRelativeTime(reply.SentAt)</span>
                        </div>
                        <div class="reply-content">@reply.Content</div>
                    </div>
                }
            }
        </div>

        <MessageInput Placeholder="Reply in thread…"
                      ButtonLabel="Reply"
                      OnSend="OnReplySend" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter] public List<Message> Replies { get; set; } = [];
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySend { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }
}

