        {
            <div class="main-header">
                <h2># @activeChannel.Name</h2>
                <span class="main-description">@activeChannel.Description</span>
            </div>

            <MessageList @ref="messageListRef"
                         Messages="messages"
                         ThreadSummaries="threadSummaries"
                         IsLoading="isLoadingMessages"
                         HasMore="hasMoreMessages"
                         OnLoadMore="LoadOlderMessages"
                         OnReplyClicked="OpenThread"
                         OnReactionAdded="AddReaction" />

            <MessageInput Placeholder="@($"Message #{activeChannel.Name}")"
                          OnSend="SendMessage" />
        }
        else
        {
            <div class="no-channel">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (threadOpen)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="threadRootMessage"
