@code {
    private List<Channel> channels = [];
    private int? activeChannelId;
    private Channel? activeChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = [];
    private bool isLoadingMessages;
    private bool hasMoreMessages = true;
    private const int PageSize = 30;

    private bool threadOpen;
    private int? threadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private bool isLoadingThread;

    private MessageList? messageListRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (activeChannelId == channelId)
            return;

        activeChannelId = channelId;
        activeChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messages = [];
        hasMoreMessages = true;
        threadSummaries = [];
        CloseThreadInternal();

        await LoadMessages();
        _ = ChatService.MarkChannelReadAsync(channelId);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }
    }

    private async Task LoadMessages()
    {
        if (activeChannelId is null)
            return;

        isLoadingMessages = true;

        var newMessages = await ChatService.GetMessagesAsync(activeChannelId.Value, messages.Count, PageSize);

        if (newMessages.Count < PageSize)
        {
            hasMoreMessages = false;
        }

        // Prepend older messages (API returns oldest-first for skip/take)
        messages.InsertRange(0, newMessages);
        isLoadingMessages = false;
    }

    private async Task LoadOlderMessages()
    {
        await LoadMessages();
    }

    private async Task SendMessage(string content)
    {
        if (activeChannelId is null)
            return;

        var sent = await ChatService.SendMessageAsync(activeChannelId.Value, content, null);
        messages.Add(sent);

        if (messageListRef is not null)
        {
            await messageListRef.ScrollToBottom();
        }
    }

    private async Task OpenThread(int rootMessageId)
    {
        threadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadOpen = true;
        isLoadingThread = true;
        threadReplies = [];

        StateHasChanged();

        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        isLoadingThread = false;

        // Update thread summary
        if (threadReplies.Count > 0)
        {
            threadSummaries[rootMessageId] = new ThreadSummary(
                rootMessageId,
                threadReplies.Count,
                threadReplies[^1].SentAt);
        }
    }

    private void CloseThread()
    {
        CloseThreadInternal();
    }

    private void CloseThreadInternal()
    {
        threadOpen = false;
        threadRootId = null;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannelId is null || threadRootId is null)
            return;

        var reply = await ChatService.SendMessageAsync(activeChannelId.Value, content, threadRootId.Value);
        threadReplies.Add(reply);

        // Update thread summary
        threadSummaries[threadRootId.Value] = new ThreadSummary(
            threadRootId.Value,
            threadReplies.Count,
            reply.SentAt);
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        // Optimistically update the local message
        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
        if (msg is not null)
        {
            var idx = messages.IndexOf(msg);
            var reactions = new List<Reaction>(msg.Reactions);
            var existing = reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
            if (existing is not null)
            {
                reactions.Remove(existing);
                var users = new List<string>(existing.Users) { "You" };
                reactions.Add(new Reaction(args.Emoji, users));
            }
            else
            {
                reactions.Add(new Reaction(args.Emoji, ["You"]));
            }

            messages[idx] = msg with { Reactions = reactions };
        }
    }
}

