toolArgs.file_text:
.chat-container {
    display: flex;
    flex: 1;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.chat-main.thread-visible {
    /* Main area shrinks when thread is open */
}

.chat-thread {
    width: 25%;
    min-width: 280px;
    max-width: 420px;
    flex-shrink: 0;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    background: #fff;
    flex-shrink: 0;
}

.main-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

.main-description {
    font-size: 0.82rem;
    color: #888;
}

.no-channel {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

